import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";import{y as n,x as s,M as t}from"./framework.e2299119.js";const p='{"title":"Adding Apline.js to Laravel using Laravel Mix","description":"","frontmatter":{"title":"Adding Apline.js to Laravel using Laravel Mix","date":"2022-06-22T00:00:00.000Z","author":"Takeshi Yu","twitter":"@easternsoul1","gravatar":"50d500a03e573764bceb72cdffee6f7a"},"headers":[{"level":2,"title":"安裝 Apline.js","slug":"安裝-apline-js"},{"level":2,"title":"測試","slug":"測試"}],"relativePath":"posts/install-aplinejs-with-laravel-mix.md","lastUpdated":1655951279346}',e={},o=[t('<p><a href="https://alpinejs.dev/" target="_blank" rel="noopener noreferrer">Alpine.js</a> 是最近在社群裡常出現的一個輕量的 JavaScript 框架，它與 <a href="https://laravel-livewire.com/" target="_blank" rel="noopener noreferrer">Laravel Livewire</a> 都是由 <a href="https://github.com/calebporzio" target="_blank" rel="noopener noreferrer">Caleb Porzio</a> 所開發出來的，兩者互相搭配後，可以與前端頁面達到交互作用的效果，對於不是很熟悉前端技術的我而言，是個很不錯的選擇！</p><hr><p>雖然說直接透過使用 <code>script tag</code> 來安裝使用 Apline.js 也是可以的，<a href="https://alpinejs.dev/essentials/installation#from-a-script-tag" target="_blank" rel="noopener noreferrer">官方文件</a> 也有提到，但是如果能把需要用到的 JavaScript 以及 CSS 透過 Webpack 加入到 Laravel 裡就好了，這樣可以透過 <a href="https://laravel.com/docs/master/mix" target="_blank" rel="noopener noreferrer">Compiling Assets (Mix)</a> 將多個檔案都壓縮在一起，加快載入的速度，而實際使用時，只需要加上 <code>app.js</code> 以及 <code>app.css</code> 就好，也比較乾淨。</p><h2 id="安裝-apline-js" tabindex="-1">安裝 Apline.js <a class="header-anchor" href="#安裝-apline-js" aria-hidden="true">#</a></h2><p>依照 <a href="https://alpinejs.dev/essentials/installation#as-a-module" target="_blank" rel="noopener noreferrer">官方文件</a> 的描述，在專案目錄裡執行 <code>npm</code> 來安裝：</p><div class="language-shell"><pre><code><span class="token function">npm</span> <span class="token function">install</span> alpinejs\n</code></pre></div><p>安裝成功後，需要編輯 <code>resources/js/app.js</code> 載入 <code>Alpine.js</code>:</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token string">&#39;./bootstrap&#39;</span><span class="token punctuation">;</span>\n\n<span class="token comment">// 加入下列程式碼...</span>\n<span class="token keyword">import</span> Alpine <span class="token keyword">from</span> <span class="token string">&#39;alpinejs&#39;</span><span class="token punctuation">;</span>\nwindow<span class="token punctuation">.</span>Alpine <span class="token operator">=</span> Alpine<span class="token punctuation">;</span>\nAlpine<span class="token punctuation">.</span><span class="token function">start</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre></div><p>完成後，接著執行：</p><div class="language-shell"><pre><code><span class="token function">npm</span> run dev\n</code></pre></div><p>執行完成後，可以打開 <code>public/js/app.js</code> 查看是否有成功加入 Alpine.js。</p><h2 id="測試" tabindex="-1">測試 <a class="header-anchor" href="#測試" aria-hidden="true">#</a></h2><p>調整一下預設的 <code>resources/views/welcome.blade.php</code>:</p><div class="language-html"><pre><code><span class="token doctype"><span class="token punctuation">&lt;!</span><span class="token doctype-tag">DOCTYPE</span> <span class="token name">html</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span> <span class="token attr-name">lang</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>{{ str_replace(<span class="token punctuation">&#39;</span>_<span class="token punctuation">&#39;</span>, <span class="token punctuation">&#39;</span>-<span class="token punctuation">&#39;</span>, app()-&gt;getLocale()) }}<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>head</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>meta</span> <span class="token attr-name">charset</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>utf-8<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>meta</span> <span class="token attr-name">name</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>viewport<span class="token punctuation">&quot;</span></span> <span class="token attr-name">content</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>width=device-width, initial-scale=1<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>title</span><span class="token punctuation">&gt;</span></span>Alpine.js Demo<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>title</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>stylesheet<span class="token punctuation">&quot;</span></span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>{{ asset(<span class="token punctuation">&#39;</span>css/app.css<span class="token punctuation">&#39;</span>) }}<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>text/javascript<span class="token punctuation">&quot;</span></span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>{{ asset(<span class="token punctuation">&#39;</span>js/app.js<span class="token punctuation">&#39;</span>) }}<span class="token punctuation">&quot;</span></span> <span class="token attr-name">defer</span><span class="token punctuation">&gt;</span></span><span class="token script"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>head</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>antialiased<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">x-data</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>{ show: true }<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>button</span> <span class="token attr-name">@click</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>show = !show<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>Hide<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>button</span><span class="token punctuation">&gt;</span></span>\n            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span> <span class="token attr-name">x-show</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>show<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>Hello World! Alpine.js<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span>\n        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>因為 <code>show</code> 預設為 <code>true</code>，因此打開頁面後就可以直接看到 <code>Hello World! Alpine.js</code> 的訊息，若點擊按鈕 <code>Hide</code>，則 <code>show</code> 會被設定為 <code>false</code>，訊息就會被隱藏了。</p><p>Alpine.js 成功安裝！</p>',16)];var c=a(e,[["render",function(a,t,p,e,c,l){return s(),n("div",null,o)}]]);export{p as __pageData,c as default};
